from flask import Flask, request, jsonify
import face_recognition
import numpy as np

app = Flask(__name__)

# Load employee photos and encode them
employee_photos = ['path_to_photo1.jpg', 'path_to_photo2.jpg', ...]
employee_encodings = [face_recognition.face_encodings(face_recognition.load_image_file(photo))[0] for photo in employee_photos]

@app.route('/recognize_face', methods=['POST'])
def recognize_face():
    image_data = request.files['image']
    unknown_image = face_recognition.load_image_file(image_data)
    unknown_encoding = face_recognition.face_encodings(unknown_image)[0]
    
    # Compare the unknown encoding to all employee encodings
    distances = [face_recognition.face_distance([employee_encoding], unknown_encoding) for employee_encoding in employee_encodings]
    min_distance_index = np.argmin(distances)
    min_distance = distances[min_distance_index]
    
    if min_distance < 0.6:  # Adjust threshold as needed
        confidence_score = 1 - min_distance
        return jsonify({'employee': 'Employee ' + str(min_distance_index + 1), 'confidence': confidence_score})
    else:
        return jsonify({'employee': 'Unknown', 'confidence': 0})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)